interface UserInfo { age: number; }

// We create a dictionary mapping string IDs to UserInfo objects
type UserDatabase = Record<string, UserInfo>;

const db: UserDatabase = {
  "alice123": { age: 25 },
  "bob456": { age: 30 }
};

// TS brilliantly knows whatever you fetch is fundamentally UserInfo
let bobAge = db["bob456"].age;

type Role = "admin" | "user" | "guest";

// We mathematically FORCE the dictionary to perfectly contain exactly these 3 keys!
type Permissions = Record<Role, boolean>;

const roleAccess: Permissions = {
  admin: true,
  user: true,
  // ERROR! 'guest' property is strictly missing!
};
